#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <math.h>

#define MAX_ARMS 10

// Structure to hold bandit state
typedef struct {
 int n_arms;
 double epsilon;
 int counts[MAX_ARMS];
 double values[MAX_ARMS];
 double true_probs[MAX_ARMS];
} Bandit;

// Initialize bandit with given parameters
void init_bandit(Bandit *bandit, int n_arms, double epsilon, double *true_probs) {
 bandit->n_arms = n_arms;
 bandit->epsilon = epsilon;

 for (int i = 0; i < n_arms; i++) {
 bandit->counts[i] = 0;
 bandit->values[i] = 0.0;
 bandit->true_probs[i] = true_probs[i];
 }
}

// Pull an arm and return reward (1 with probability, 0 otherwise)
int pull_arm(Bandit *bandit, int arm) {
 double rand_val = (double)rand() / RAND_MAX;
 return (rand_val < bandit->true_probs[arm]) ? 1 : 0;
}

// Select arm using epsilon-greedy strategy
int select_arm(Bandit *bandit) {
 double rand_val = (double)rand() / RAND_MAX;

 if (rand_val < bandit->epsilon) {
 // Exploration: random arm
 return rand() % bandit->n_arms;
 } else {
 // Exploitation: find arm with highest estimated value
 int best_arm = 0;
 double best_value = bandit->values[0];

 for (int i = 1; i < bandit->n_arms; i++) {
 if (bandit->values[i] > best_value) {
 best_value = bandit->values[i];
 best_arm = i;
 }
 }
 return best_arm;
 }
}

// Update value estimate for an arm using incremental mean
void update(Bandit *bandit, int arm, int reward) {
 bandit->counts[arm]++;
 int n = bandit->counts[arm];
 // Q(a) = Q(a) + (r - Q(a)) / n
 bandit->values[arm] += ((double)reward - bandit->values[arm]) / n;
}

// Run epsilon-greedy algorithm
double run_epsilon_greedy(Bandit *bandit, int n_steps) {
 double total_reward = 0.0;

 for (int t = 0; t < n_steps; t++) {
 int arm = select_arm(bandit);
 int reward = pull_arm(bandit, arm);
 update(bandit, arm, reward);
 total_reward += reward;
 }

 return total_reward;
}

// Calculate regret (difference from optimal)
double calculate_regret(double total_reward, double *true_probs, int n_arms, int n_steps) {
 double max_prob = true_probs[0];
 for (int i = 1; i < n_arms; i++) {
 if (true_probs[i] > max_prob) {
 max_prob = true_probs[i];
 }
 }
 double optimal = n_steps * max_prob;
 return optimal - total_reward;
}

int main(int argc, char *argv[]) {
 // Default parameters
 int n_arms = 5;
 int n_steps = 1000;
 int n_runs = 100;
 double epsilon = 0.1;

 // True reward probabilities (unknown to algorithm)
 double true_probs[MAX_ARMS] = {0.3, 0.5, 0.7, 0.4, 0.6};

 // Parse command-line arguments
 if (argc >= 2) n_arms = atoi(argv[1]);
 if (argc >= 3) n_steps = atoi(argv[2]);
 if (argc >= 4) n_runs = atoi(argv[3]);
 if (argc >= 5) epsilon = atof(argv[4]);

 // Initialize random seed
 srand(time(NULL));

 printf("=== Epsilon-Greedy Multi-Armed Bandit ===\n");
 printf("Number of arms: %d\n", n_arms);
 printf("Steps per run: %d\n", n_steps);
 printf("Number of runs: %d\n", n_runs);
 printf("Epsilon: %.2f\n", epsilon);
 printf("True probabilities: ");
 for (int i = 0; i < n_arms; i++) {
 printf("%.2f ", true_probs[i]);
 }
 printf("\n\n");

 // Find optimal arm
 int best_arm = 0;
 double max_prob = true_probs[0];
 for (int i = 1; i < n_arms; i++) {
 if (true_probs[i] > max_prob) {
 max_prob = true_probs[i];
 best_arm = i;
 }
 }
 printf("Best arm: %d with probability %.2f\n", best_arm, max_prob);
 printf("Theoretical maximum: %.2f\n\n", n_steps * max_prob);

 // Run multiple experiments
 double total_reward_sum = 0.0;
 double total_regret_sum = 0.0;

 for (int run = 0; run < n_runs; run++) {
 Bandit bandit;
 init_bandit(&bandit, n_arms, epsilon, true_probs);

 double reward = run_epsilon_greedy(&bandit, n_steps);
 total_reward_sum += reward;
 total_regret_sum += calculate_regret(reward, true_probs, n_arms, n_steps);
 }

 double avg_reward = total_reward_sum / n_runs;
 double avg_regret = total_regret_sum / n_runs;

 printf("=== Results over %d runs ===\n", n_runs);
 printf("Average Total Reward: %.2f\n", avg_reward);
 printf("Average Regret: %.2f\n", avg_regret);
 printf("Reward Rate: %.2f%%\n", (avg_reward / n_steps) * 100);

 return 0;
}
